import java.io.*;
import java.util.*;

public class Main {
    static class Item {
        long value;
        long weight;
        double ratio;
        Item(long v, long w) {
            value = v;
            weight = w;
            ratio = (double) v / w;
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append('\n');
        }
        // Replace escaped "\n" sequences that may appear in some test definitions
        String all = rawInput.toString().replace("\\n", " ");
        Scanner sc = new Scanner(all);
        sc.useLocale(Locale.US);
        StringBuilder sb = new StringBuilder();
        int T = sc.nextInt();
        for (int tc = 0; tc < T; tc++) {
            int N = sc.nextInt();
            long C = sc.nextLong();
            long[] vals = new long[N];
            long[] wts = new long[N];
            for (int i = 0; i < N; i++) vals[i] = sc.nextLong();
            for (int i = 0; i < N; i++) wts[i] = sc.nextLong();
            Item[] items = new Item[N];
            for (int i = 0; i < N; i++) items[i] = new Item(vals[i], wts[i]);
            Arrays.sort(items, (a, b) -> Double.compare(b.ratio, a.ratio));
            double total = 0.0;
            long used = 0;
            for (Item it : items) {
                if (used + it.weight <= C) {
                    used += it.weight;
                    total += it.value;
                } else {
                    long remain = C - used;
                    if (remain > 0) {
                        total += it.value * ((double) remain / it.weight);
                    }
                    break;
                }
            }
            sb.append(String.format(Locale.US, "%.6f", total));
            if (tc != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

